'use strict';

// pdf-parse v1.1.4 is published without lib/pdf-parse.js (broken npm publish).
// This script recreates the missing file using the bundled pdfjs v2.0.550.
// Run automatically via postinstall.

const fs = require('fs');
const path = require('path');

const dest = path.join(__dirname, '..', 'node_modules', 'pdf-parse', 'lib', 'pdf-parse.js');

const content = `'use strict';

// Auto-generated by scripts/patch-pdf-parse.js — do not edit manually.
const pdfjs = require('./pdf.js/v2.0.550/build/pdf.js');

async function PDFParser(dataBuffer, options) {
  const max = (options && options.max) || 0;

  const data = Buffer.isBuffer(dataBuffer)
    ? new Uint8Array(dataBuffer.buffer, dataBuffer.byteOffset, dataBuffer.byteLength)
    : new Uint8Array(dataBuffer);

  const pdf = await pdfjs.getDocument({ data }).promise;

  const numPages = pdf.numPages;
  const limit = max > 0 ? Math.min(max, numPages) : numPages;
  let text = '';

  for (let i = 1; i <= limit; i++) {
    const page = await pdf.getPage(i);
    const content = await page.getTextContent({ normalizeWhitespace: false });
    let pageText = '';
    let lastY = null;
    for (const item of content.items) {
      if (lastY !== null && lastY !== item.transform[5]) {
        pageText += '\\n';
      }
      pageText += item.str;
      lastY = item.transform[5];
    }
    text += pageText + '\\n\\n';
  }

  let info = {};
  try {
    const meta = await pdf.getMetadata();
    if (meta && meta.info) info = meta.info;
  } catch (_) { /* metadata optional */ }

  return { numpages: numPages, info, text };
}

module.exports = PDFParser;
`;

try {
  const dir = path.dirname(dest);
  if (!fs.existsSync(dir)) {
    fs.mkdirSync(dir, { recursive: true });
  }
  fs.writeFileSync(dest, content);
  console.log('patch-pdf-parse: wrote', dest);
} catch (err) {
  console.warn('patch-pdf-parse: could not write file:', err.message);
}
